// Build Claude messages from Slack thread history
const webhook = $('Slack Webhook').first().json;
const event = webhook.body.event;
const threadResp = $input.first().json;

const botUserId = webhook.body.authorizations?.[0]?.user_id || 'BOT';

let messages = [];

if (threadResp.ok && threadResp.messages) {
  for (const msg of threadResp.messages) {
    // Strip @mention of our bot from text
    let text = (msg.text || '').replace(new RegExp(`<@${botUserId}>`, 'g'), '').trim();
    if (!text) continue;

    if (msg.bot_id || msg.user === botUserId) {
      messages.push({ role: 'assistant', content: text });
    } else {
      messages.push({ role: 'user', content: text });
    }
  }
} else {
  // No thread history, just use the current message
  let text = (event.text || '').replace(new RegExp(`<@${botUserId}>`, 'g'), '').trim();
  messages.push({ role: 'user', content: text });
}

// Ensure messages start with user role
if (messages.length > 0 && messages[0].role !== 'user') {
  messages = messages.filter(m => m.role === 'user' || messages.indexOf(m) > 0);
}

return [{
  json: {
    messages,
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    user: event.user
  }
}];

