// Execute tool calls from Claude
const response = $input.first().json;
const prevMessages = $('Build Claude Messages').first().json.messages;
const channel = $('Build Claude Messages').first().json.channel;
const thread_ts = $('Build Claude Messages').first().json.thread_ts;

let toolResults = [];
let assistantContent = response.content || [];

for (const block of assistantContent) {
  if (block.type === 'tool_use') {
    let result = '';
    try {
      if (block.name === 'execute_javascript') {
        // Execute JS in a sandboxed way
        const fn = new Function(block.input.code);
        result = String(fn() ?? 'Code executed successfully (no return value)');
      } else if (block.name === 'search_web') {
        result = `[Web search not implemented in this version. Query: ${block.input.query}]`;
      } else {
        result = `Unknown tool: ${block.name}`;
      }
    } catch (e) {
      result = `Error: ${e.message}`;
    }
    toolResults.push({
      type: 'tool_result',
      tool_use_id: block.id,
      content: result.substring(0, 4000)
    });
  }
}

// Build messages for the follow-up Claude call
const newMessages = [
  ...prevMessages,
  { role: 'assistant', content: assistantContent },
  { role: 'user', content: toolResults }
];

return [{ json: { messages: newMessages, channel, thread_ts } }];

