// Extract text response from Claude
const response = $input.first().json;
const content = response.content || [];
const channel = $('Build Claude Messages').first().json.channel;
const thread_ts = $('Build Claude Messages').first().json.thread_ts;

let text = '';
for (const block of content) {
  if (block.type === 'text') {
    text += block.text;
  }
}

if (!text) text = '(No response generated)';

// Slack has a 4000 char limit per message; split if needed
const maxLen = 3900;
const chunks = [];
for (let i = 0; i < text.length; i += maxLen) {
  chunks.push(text.substring(i, i + maxLen));
}

return chunks.map(chunk => ({
  json: { text: chunk, channel, thread_ts }
}));
